var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"말도 안 돼…….","JPN":"ありえない……","ENG":"No way...","TWN":"不可能……"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이렇게 가까운 곳에 이런 시설이 숨겨져 있었다니……!","JPN":"こんな近くに、こんな施設が隠されていたなんて……！","ENG":"I didn't know a facility like this was hiding so close by...!","TWN":"這附近怎麼會還藏著這種建築……！"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후훗, 놀랐어?","JPN":"ふふ、驚いた？","ENG":"Fu fuu, surprised?","TWN":"呵呵，你很驚訝？"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"여긴 관리국의 전초기지 같은 곳이거든.","JPN":"ここは管理局の前哨基地みたいな場所よ。","ENG":"This place used to be like a frontier base for the Administration.","TWN":"這裡算是管理局的前哨基地。"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"현실세계에 잔류하고 있는 동안 우리는 보통 전초기지에 머물면서 작전을 대기하지.","JPN":"現実世界に残留している間、私たちは作戦が開始するまで前哨基地で待機するの。","ENG":"While we stay in the real world, we usually reside in this frontier base and wait for operations.","TWN":"當我們逗留在現世時，通常會留在前哨站等待作戰。"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"농담하지 마! 이래 봬도 소방관이라고!","JPN":"ふざけるな、アタシは消防士なんだぞ！","ENG":"Stop joking! I'm a firefighter, you know!","TWN":"別開玩笑！別看我只是個消防員！"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"담당 구역 내에 있는 가로수의 개수와 쓰레기통의 위치까지 전부 외우고 있어!","JPN":"担当区域内のことなら並木の数からゴミ箱の場所まで全部覚えている！","ENG":"This was my jurisdiction. I even memorized the number of street lamps and the location of all the trash cans!","TWN":"但我記得我們負責片區裡的每一條路！甚至是垃圾桶的位置！"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이런 시설이 있다는 걸, 내가 몰랐을 리가 없다고!","JPN":"こんな施設があるのにアタシが気づけなかったなんて……！","ENG":"There's no way that I didn't know about a facility like this!","TWN":"如果這裡有這樣的建築，我不可能不知道！"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"안심해. 모르는 게 정상이니까.","JPN":"安心して。知らなくて当然よ。","ENG":"Don't worry. It's normal that you didn't know.","TWN":"放心。你不知道很正常。"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"현실세계에 지어진 관리국 시설은 대부분 <color=#ffd34c>인지 왜곡</color>기술을 사용하고 있거든.","JPN":"現実世界にある管理局施設のほとんどは、<color=#ffd34c>認知歪曲</color>技術を用いてるの。","ENG":"The Administration's facilities in the real world usually use a technology called <color=#ffd34c>awareness distortion</color>.","TWN":"管理局在現世中建造的大多數設施都使用了<color=#ffd34c>認知扭曲</color>科技。"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"인지 왜곡?","JPN":"認知歪曲？","ENG":"Awareness distortion?","TWN":"認知扭曲？"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"기본적으로 인간은 자기가 보고 싶어하는 것만 보기 마련이야.","JPN":"人間はね基本的に、自分の見たいものしか目に入らないの。","ENG":"Basically, humans only see what they want to see.","TWN":"基本上，人類只會看到他們想看到的東西。"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그런 심리를 이용해서, 기지 주변에 인지를 왜곡시키는 파장을 발생시키는 거지.","JPN":"そういう心理を利用して、基地の周りに認知を歪ませる波長を発生させるのよ。","ENG":"We use that psychology, and generate waves that distort their perception around the base.","TWN":"利用這種心理，在基地周圍散發了扭曲認知的波長。"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 결과, 이 기지는 실재하지만, 평범한 사람들에게는 실재하지 않는 것처럼 여겨지게 돼.","JPN":"おかげでこの基地は実在しながらも普通の人間には認知されないってわけ。","ENG":"As a result, the base exists but it appears not to exist to ordinary people.","TWN":"成果就是，這個基地雖然真實存在，但對於普通人來說卻並不存在。"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐, 음모론에 심취한 괴짜들은 가끔 기지를 발견하기도 하는 모양이지만.","JPN":"陰謀論を信じる変わり者に気づかれることは時々あるみたいだけど。","ENG":"Well, some conspiracy theory nerds occasionally seem to discover it from time to time.","TWN":"唔，不過似乎有時候也會被某些陰謀論者發現……"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이런 짓까지 해가면서……. 대체 너희는 뭘 숨기고 싶어하는 건데?","JPN":"こんなことまでして……いったいおまえたちは何を隠している？","ENG":"What are you trying to hide... by going through all this?","TWN":"做到這種地步……你們把自己藏起來，究竟是想要做什麼？"},"stage":{"bg":"LIFT","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"흐음, 아무래도 도착한 거 같네.","JPN":"もう着いたみたいね。","ENG":"Hmm, I think we're here.","TWN":"嗯，看來我們已經到了。"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"자세한 이야기는 안에 들어가서 하자. 모두 우리를 기다리고 있으니까.","JPN":"詳しい話は中に入ってからしましょうか。みんな私たちを待っているよ。","ENG":"Let's talk details once we're inside. They're all waiting for you.","TWN":"大家都在等我們，詳細的我們進去再說吧？"},"stage":{"bg":"LIFT","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"다녀왔어~ 다들 나 없는 동안 별 일 없었지?","JPN":"ただいま～留守の間、何もなかった？","ENG":"I'm back! Did anything happen while I was gone?","TWN":"我回來了～我不在的這段時間，沒發生什麼事吧？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FOX_YAKSHA_NPC_NULL","text":{"KOREA":"와아, 부전대장님이다! 부전대장님이 돌아왔어!","JPN":"わあ、副戦隊長だ！　副戦隊長が帰ってきた！","ENG":"Yay! It's Deputy Commander! She's back!","TWN":"哇，是副戰隊長！副戰隊長回來了！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RACOON_YAKSHA_NPC_NULL","text":{"KOREA":"아! 오늘도 고생하셨습니다, 스위프트 씨.","JPN":"あっ、今日もお疲れ様です。スウィフトさん。","ENG":"Oh! Good job today, Ms. Swift.","TWN":"啊！你今天也辛苦了，斯威福特副戰隊長。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HORN_YAKSHA_NPC_NULL","text":{"KOREA":"어서 와, 당근 케이크가 맛있게 구워졌는데 먹을래?","JPN":"おかえり。おいしいニンジンケーキが焼けたけど、食べる？","ENG":"Welcome back. I made some delicious carrot cake. Do you want some?","TWN":"歡迎回來，我烤了美味的紅蘿蔔蛋糕，要嚐嚐嗎？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"여기 있는 사람들 전부 동물의 특징을 가지고 있어…… ","JPN":"ここにいる人はみんな、体の一部に動物の特徴が現れているの…… ","ENG":"All the people here have characteristics of animals...","TWN":"這裡的每個人都擁有動物的特徵……"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};